#!/usr/bin/env python3\n\"\"\"\nS1/S2 Decision Tracking System for Refugee Displacement\n\nThis module implements tracking and analysis of System 1 vs System 2 decision-making\nin refugee displacement scenarios, building on Flee's existing cognitive system.\n\"\"\"\n\nimport sys\nimport csv\nimport json\nfrom pathlib import Path\nfrom collections import defaultdict\nfrom dataclasses import dataclass\nfrom typing import Dict, List, Optional, Tuple\n\n# Add current directory to path for Flee imports\ncurrent_dir = Path(__file__).parent\nif str(current_dir) not in sys.path:\n    sys.path.insert(0, str(current_dir))\n\n@dataclass\nclass S1S2Decision:\n    \"\"\"Record of a single S1 or S2 decision\"\"\"\n    time: int\n    agent_id: int\n    system2_active: bool\n    conflict_level: float\n    connections: int\n    movechance: float\n    location_name: str\n    destination_name: Optional[str]\n    route_quality: float\n    decision_factors: Dict\n\nclass S1S2DecisionTracker:\n    \"\"\"Tracks and analyzes S1 vs S2 decisions in refugee displacement scenarios\"\"\"\n    \n    def __init__(self, output_dir: str = \"s1s2_analysis\"):\n        self.output_dir = Path(output_dir)\n        self.output_dir.mkdir(exist_ok=True)\n        \n        # Decision storage\n        self.s1_decisions: List[S1S2Decision] = []\n        self.s2_decisions: List[S1S2Decision] = []\n        self.all_decisions: List[S1S2Decision] = []\n        \n        # Analysis results\n        self.analysis_results = {}\n        \n    def track_decision(self, agent, system2_active: bool, movechance: float, \n                      route: List, time: int, decision_factors: Dict) -> None:\n        \"\"\"Track a single S1 or S2 decision for analysis\"\"\"\n        \n        # Calculate route quality (simple metric: inverse of route length)\n        route_quality = 1.0 / max(1, len(route)) if route else 0.0\n        \n        # Get destination name\n        destination_name = route[-1].name if route else None\n        \n        # Create decision record\n        decision = S1S2Decision(\n            time=time,\n            agent_id=getattr(agent, 'id', id(agent)),\n            system2_active=system2_active,\n            conflict_level=agent.location.conflict,\n            connections=agent.attributes.get('connections', 0),\n            movechance=movechance,\n            location_name=agent.location.name,\n            destination_name=destination_name,\n            route_quality=route_quality,\n            decision_factors=decision_factors\n        )\n        \n        # Store decision\n        self.all_decisions.append(decision)\n        if system2_active:\n            self.s2_decisions.append(decision)\n        else:\n            self.s1_decisions.append(decision)\n    \n    def analyze_behavioral_differences(self) -> Dict:\n        \"\"\"Comprehensive analysis of S1 vs S2 behavioral differences\"\"\"\n        # Simple analysis for now\n        total_decisions = len(self.all_decisions)\n        s2_activations = len(self.s2_decisions)\n        \n        self.analysis_results = {\n            'system2_activation': {\n                'total_decisions': total_decisions,\n                's2_activations': s2_activations,\n                's2_activation_rate': s2_activations / total_decisions if total_decisions > 0 else 0\n            }\n        }\n        \n        return self.analysis_results\n    \n    def print_summary(self) -> None:\n        \"\"\"Print summary report to console\"\"\"\n        if not self.analysis_results:\n            self.analyze_behavioral_differences()\n        \n        results = self.analysis_results\n        \n        print(f\"\\n🧠 S1/S2 ANALYSIS SUMMARY\")\n        print(f\"Total decisions: {results['system2_activation']['total_decisions']}\")\n        print(f\"S2 activations: {results['system2_activation']['s2_activations']}\")\n        print(f\"S2 activation rate: {results['system2_activation']['s2_activation_rate']:.1%}\")\n\nif __name__ == \"__main__\":\n    print(\"🧠 S1/S2 Decision Tracking System for Refugee Displacement\")\n    tracker = S1S2DecisionTracker()\n    print(\"✅ S1/S2 Decision Tracker ready!\")\n"